array_filter(
			array_map( 'sanitize_text_field', $input ),
			function ( $slug ) use ( $valid_slugs ) {
				return in_array( $slug, $valid_slugs, true );
			}
		)

printf(
			/* translators: the plugin name. */
			esc_html__( 'There is a new version of %1$s available.', 'easy-digital-downloads' ),
			esc_html( $plugin['Name'] )
		)

array_filter(
				$config,
				function ( $slug ) use ( $all_slugs ) {
					return in_array( $slug, $all_slugs, true );
				}
			)

